from flask import Flask, request
from elasticsearch import Elasticsearch
app = Flask(__name__)
es = Elasticsearch([{'host': 'localhost', 'port': 9200}]) # Change host and port according to your configuration.

@app.route('/execute_script', methods=['POST'])
def execute_script():
    if request.method == 'POST' and 'req.json' in request.get_json() and 'script' in request.get_json()['req.json']:
        script = request.get_json()['req.json']['script']  # Retrieve the script from user input.
        res = es.search(
            body={
                "query": {
                    "function_score": {
                        "functions": [
                            {"inline": {"source": script, "params": {}}}
                        ]
                    }
                }
            },
            _source=False  # Disable the source field to save bandwidth.
        )
        return res  # Return response from Elasticsearch server.
    else:
        return {'error': 'invalid request'}, 400  # Handle invalid requests.

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=5000)  # Run the server on port 5000 of localhost.